// やまやま牧場：牛舎画面ロジック（フェーズ1）
// プロトタイプ 指示書/ushiya_v3.html をベースに、実際のセーブデータ(yamayama_loop_v1)と連動させたもの。
// i18n.js / common.js が先に読み込まれている前提。

const W = 375, H = 666;
const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');
ctx.imageSmoothingEnabled = false;

// ── 牛房データ（レイアウトはプロトタイプを流用） ──
// 現時点ではふうか(cow_001)のみをs0に配置。s1〜s7は空き牛房として表示する。
// s3・s7は現在の仕様では埋める予定がない予備枠。
// barn_bg画像は3行×2列＝6部屋分しか描かれていない（4行目は存在しない）ため、
// 6部屋ぶんだけ配置する。id は指示書の母牛/子牛スロット命名(s0〜s2, s4〜s6)を踏襲し、
// 存在しない空き予備枠(s3, s7)は削除する。
const STALLS = [
  { id:'s0', cx:97,  cy:130, type:'cow'   }, // 母牛①
  { id:'s1', cx:277, cy:130, type:'empty' }, // 母牛②
  { id:'s2', cx:97,  cy:300, type:'empty' }, // 母牛③
  { id:'s4', cx:277, cy:300, type:'empty' }, // 子牛①
  { id:'s5', cx:97,  cy:495, type:'empty' }, // 子牛②
  { id:'s6', cx:277, cy:495, type:'empty' }, // 子牛③
];
const HITBOXES = [
  { id:'s0', x1:15,  y1:55,  x2:185, y2:215 },
  { id:'s1', x1:190, y1:55,  x2:360, y2:215 },
  { id:'s2', x1:15,  y1:215, x2:185, y2:410 },
  { id:'s4', x1:190, y1:215, x2:360, y2:410 },
  { id:'s5', x1:15,  y1:410, x2:185, y2:605 },
  { id:'s6', x1:190, y1:410, x2:360, y2:605 },
];
const PLAYER_HOME = { x:187, y:330 };
// 入口付近（牛舎の下端、通路の出口）をタップしても牧場へ戻れるようにする
const EXIT_POINT = { x:187, y:620 };
const EXIT_HITBOX = { x1:0, y1:605, x2:375, y2:666 };

const loopState = loadLoopState();
const cow = loopState.cows[0]; // フェーズ1では1頭のみ
STALLS[0].cowRef = cow;

// ── 画像ロード ──
const IMG = {};
function loadImg(key, src) {
  return new Promise(res => {
    const i = new Image();
    i.onload = () => { IMG[key] = i; res(); };
    i.onerror = () => res();
    i.src = src;
  });
}

// ── ブチ牛パターン生成（プロトタイプから流用） ──
function makeRng(seed) {
  let s = seed >>> 0;
  return () => {
    s = (s + 0x6D2B79F5) >>> 0;
    let t = Math.imul(s ^ (s >>> 15), 1 | s);
    t = Math.imul(t ^ (t >>> 7), 61 | t) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
function isFur(r, g, b) { return (r + g + b) / 3 < 150 && Math.max(r, g, b) - Math.min(r, g, b) < 25; }
// 背景色を透過にする（CLAUDE.mdのスプライト切り出しルール準拠。画像左上の角の色を背景色とみなしtolerance内を透過にする）
function makeBgTransparent(imageData, tolerance) {
  const px = imageData.data;
  const bg = [px[0], px[1], px[2]];
  for (let i = 0; i < px.length; i += 4) {
    if (Math.abs(px[i] - bg[0]) <= tolerance && Math.abs(px[i + 1] - bg[1]) <= tolerance && Math.abs(px[i + 2] - bg[2]) <= tolerance) {
      px[i + 3] = 0;
    }
  }
}
function growBlob(mask, w, h, si, size, rng) {
  const vis = new Set(), fr = [si], res = [];
  while (fr.length && res.length < size) {
    const p = Math.floor(rng() * fr.length), idx = fr.splice(p, 1)[0];
    if (vis.has(idx)) continue;
    if (idx < 0 || idx >= w * h || !mask[idx]) continue;
    vis.add(idx); res.push(idx);
    [idx - 1, idx + 1, idx - w, idx + w].forEach(n => { if (!vis.has(n)) fr.push(n); });
  }
  return res;
}
let cowOC = null;
function preRenderCow(seed) {
  return new Promise(res => {
    const img = new Image();
    img.onload = () => {
      const rng = makeRng(seed);
      const oc = document.createElement('canvas');
      oc.width = img.width; oc.height = img.height;
      const oct = oc.getContext('2d');
      oct.drawImage(img, 0, 0);
      const d = oct.getImageData(0, 0, oc.width, oc.height);
      makeBgTransparent(d, 10);
      const px = d.data;
      const mask = new Uint8Array(oc.width * oc.height);
      for (let i = 0; i < mask.length; i++) mask[i] = isFur(px[i * 4], px[i * 4 + 1], px[i * 4 + 2]) ? 1 : 0;
      const fi = []; for (let i = 0; i < mask.length; i++) if (mask[i]) fi.push(i);
      if (fi.length) {
        const col = [[235, 225, 210], [150, 100, 60]][Math.floor(rng() * 2)];
        for (let p = 0; p < 2 + Math.floor(rng() * 3); p++) {
          growBlob(mask, oc.width, oc.height, fi[Math.floor(rng() * fi.length)], 60 + Math.floor(rng() * 140), rng)
            .forEach(i => {
              const r = px[i * 4], g = px[i * 4 + 1], b = px[i * 4 + 2];
              const br = Math.min(Math.max((r + g + b) / 3 / 30, 0.5), 1.3);
              px[i * 4] = Math.min(255, col[0] * br); px[i * 4 + 1] = Math.min(255, col[1] * br); px[i * 4 + 2] = Math.min(255, col[2] * br);
            });
        }
      }
      oct.putImageData(d, 0, 0);
      cowOC = oc; res();
    };
    img.src = 'data:image/png;base64,';
  });
}

// ── プレイヤー ──
let player = { ...PLAYER_HOME, dir: 'down', walking: false, anim: 0 };
let walkTimer = null;

function getPlayerSprite() {
  if (!player.walking) return IMG['player_' + player.dir] || null;
  const f = Math.floor(player.anim / 5) % 2;
  const map = {
    up:    ['player_up', 'player_walk_left'],  // char_walk_up.pngが無いのでleftの歩行フレームを流用
    down:  ['player_down', 'player_walk_down'],
    left:  ['player_left', 'player_walk_left'],
    right: ['player_right', 'player_walk_right'],
  };
  return IMG[(map[player.dir] || ['player_down', 'player_walk_down'])[f]] || null;
}

// ── 描画 ──
function draw() {
  ctx.clearRect(0, 0, W, H);
  if (IMG.barn_bg) ctx.drawImage(IMG.barn_bg, 0, 0, W, H);

  STALLS.forEach(s => {
    if (s.type !== 'cow' || !s.cowRef) return;
    if (cowOC) {
      const scale = 0.52 * 0.7;
      const dw = cowOC.width * scale, dh = cowOC.height * scale;
      ctx.drawImage(cowOC, s.cx - dw / 2, s.cy - dh / 2 + 8, dw, dh);
    }
    drawStatusIcons(s);
  });

  STALLS.forEach(s => {
    if (s.type === 'cow' && s.cowRef) return;
    ctx.globalAlpha = 0.35;
    ctx.fillStyle = '#8a7040';
    ctx.font = '14px serif';
    ctx.textAlign = 'center';
    ctx.fillText('🌾', s.cx, s.cy + 8);
    ctx.globalAlpha = 1.0;
  });

  const pspr = getPlayerSprite();
  if (pspr) {
    const scale = 0.65 * 2;
    const dw = pspr.width * scale, dh = pspr.height * scale;
    ctx.drawImage(pspr, player.x - dw / 2, player.y - dh / 2, dw, dh);
  } else {
    ctx.fillStyle = '#406030';
    ctx.fillRect(player.x - 8, player.y - 16, 16, 24);
  }
}

// 💩・😷の表示枠：フェーズ2で増加/発動ロジックが入るまではpoopCount=0・diseaseAlert=falseなので何も描画されない
function drawStatusIcons(stall) {
  const c = stall.cowRef;
  if (!c) return;
  if (c.diseaseAlert) {
    ctx.font = '16px serif';
    ctx.textAlign = 'left';
    ctx.fillText('😷', stall.cx - 40, stall.cy - 32);
  }
  if (c.poopCount > 0) {
    ctx.font = '14px serif';
    ctx.textAlign = 'left';
    for (let i = 0; i < Math.min(c.poopCount, 4); i++) {
      ctx.fillText('💩', stall.cx + 16 + i * 13, stall.cy + 40);
    }
  }
}

// 💩アイコンのタップ判定領域（牛房当たり判定より優先してチェックする）
function poopHitboxFor(stall) {
  return { x1: stall.cx + 8, y1: stall.cy + 24, x2: stall.cx + 82, y2: stall.cy + 56 };
}

// ── ゲームループ ──
function loop() {
  if (player.walking) player.anim++;
  draw();
  requestAnimationFrame(loop);
}

// ── タップ ──
canvas.addEventListener('click', e => {
  if (player.walking || document.getElementById('sheetOverlay').classList.contains('open') || document.getElementById('poopSheetOverlay').classList.contains('open')) return;
  const rect = canvas.getBoundingClientRect();
  const scale = W / rect.width;
  const tx = (e.clientX - rect.left) * scale;
  const ty = (e.clientY - rect.top) * scale;

  // 💩アイコンは牛房タップより優先（歩いて近づく演出はなく即座に床替えシートを開く）
  for (const s of STALLS) {
    if (s.type !== 'cow' || !s.cowRef || !(s.cowRef.poopCount > 0)) continue;
    const hb = poopHitboxFor(s);
    if (tx >= hb.x1 && tx <= hb.x2 && ty >= hb.y1 && ty <= hb.y2) {
      openPoopSheet(s);
      return;
    }
  }

  for (const hb of HITBOXES) {
    if (tx >= hb.x1 && tx <= hb.x2 && ty >= hb.y1 && ty <= hb.y2) {
      const stall = STALLS.find(s => s.id === hb.id);
      if (stall) walkToStall(stall);
      return;
    }
  }

  if (tx >= EXIT_HITBOX.x1 && tx <= EXIT_HITBOX.x2 && ty >= EXIT_HITBOX.y1 && ty <= EXIT_HITBOX.y2) {
    walkToExit();
  }
});

function walkToStall(stall) {
  clearTimeout(walkTimer);
  player.walking = true;
  const tx = stall.cx, ty = stall.cy + 55; // 牛の手前に止まる
  const dist = Math.hypot(tx - player.x, ty - player.y);

  if (Math.abs(tx - player.x) > Math.abs(ty - player.y)) player.dir = tx > player.x ? 'right' : 'left';
  else player.dir = ty > player.y ? 'down' : 'up';

  const steps = Math.max(1, Math.ceil(dist / 2.8));
  const sx = player.x, sy = player.y;
  let step = 0;

  function tick() {
    if (step >= steps) {
      player.x = tx; player.y = ty;
      player.walking = false;
      player.dir = 'up'; // 牛の方を向く
      setTimeout(() => openSheet(stall), 150);
      return;
    }
    const t = step / steps;
    player.x = sx + (tx - sx) * t;
    player.y = sy + (ty - sy) * t;
    step++;
    walkTimer = setTimeout(tick, 16);
  }
  tick();
}

function walkHome() {
  clearTimeout(walkTimer);
  player.walking = true;
  const tx = PLAYER_HOME.x, ty = PLAYER_HOME.y;
  const dist = Math.hypot(tx - player.x, ty - player.y);
  player.dir = ty < player.y ? 'up' : 'down';
  const steps = Math.max(1, Math.ceil(dist / 2.8));
  const sx = player.x, sy = player.y;
  let step = 0;
  function tick() {
    if (step >= steps) { player.x = tx; player.y = ty; player.walking = false; player.dir = 'down'; return; }
    const t = step / steps;
    player.x = sx + (tx - sx) * t; player.y = sy + (ty - sy) * t;
    step++;
    walkTimer = setTimeout(tick, 16);
  }
  tick();
}

function walkToExit() {
  clearTimeout(walkTimer);
  player.walking = true;
  const tx = EXIT_POINT.x, ty = EXIT_POINT.y;
  const dist = Math.hypot(tx - player.x, ty - player.y);
  player.dir = 'down';
  const steps = Math.max(1, Math.ceil(dist / 2.8));
  const sx = player.x, sy = player.y;
  let step = 0;
  function tick() {
    if (step >= steps) {
      player.x = tx; player.y = ty;
      setTimeout(() => { location.href = 'home.html'; }, 150);
      return;
    }
    const t = step / steps;
    player.x = sx + (tx - sx) * t; player.y = sy + (ty - sy) * t;
    step++;
    walkTimer = setTimeout(tick, 16);
  }
  tick();
}

// ── 詳細シート ──
function openSheet(stall) {
  const c = stall.cowRef;
  if (c) {
    document.getElementById('sName').textContent = c.name;
    document.getElementById('sAge').textContent = Math.floor(c.age * 0.5) + t('barn_months_suffix');
    document.getElementById('sCondLbl').textContent = t('barn_condition_label');
    document.getElementById('sCondFill').style.width = (c.condition * 10) + '%';
    document.getElementById('sCondNum').textContent = c.condition;
    document.getElementById('sQualLbl').textContent = t('barn_quality_label');
    document.getElementById('sQual').textContent = t(qualityToLabelKey(c.quality));
    const skill = SKILL_DISPLAY[c.skill];
    document.getElementById('sSkill').textContent = skill ? (skill.emoji + ' ' + t(skill.nameKey)) : '';

    const threshold = qualityThresholdFor(c.quality);
    const pct = threshold ? (loopState.qualityPoint / threshold) : 0;
    document.getElementById('sComment').textContent =
      pct <= 0.25 ? t('barn_coat_comment_1') :
      pct <= 0.50 ? t('barn_coat_comment_2').replace('{name}', c.name) :
      pct <= 0.75 ? t('barn_coat_comment_3') :
                    t('barn_coat_comment_4');

    const sc = document.getElementById('sheetCanvas');
    if (cowOC) { sc.width = cowOC.width; sc.height = cowOC.height; sc.getContext('2d').drawImage(cowOC, 0, 0); }
  } else {
    document.getElementById('sName').textContent = t('barn_empty_stall_name');
    ['sAge', 'sCondNum', 'sQual', 'sSkill'].forEach(id => document.getElementById(id).textContent = '');
    document.getElementById('sCondLbl').textContent = '';
    document.getElementById('sQualLbl').textContent = '';
    document.getElementById('sCondFill').style.width = '0%';
    document.getElementById('sComment').textContent = t('barn_empty_stall_comment');
    document.getElementById('sheetCanvas').getContext('2d').clearRect(0, 0, 100, 80);
  }
  document.getElementById('sCloseBtn').textContent = t('barn_close_btn');
  document.getElementById('sheetOverlay').classList.add('open');
}

function closeSheet() {
  document.getElementById('sheetOverlay').classList.remove('open');
  walkHome();
}

// ── 床替えシート（指示書_牛舎実装フェーズ2_床替え.md対応） ──
// 💩アイコンのタップは牛房タップ(歩いて近づく)とは別扱いで、即座にこのシートを開く
let currentPoopStall = null;

function openPoopSheet(stall) {
  currentPoopStall = stall;
  const c = stall.cowRef;
  const state = loadLoopState(); // 魔力・所持金の最新値を反映するため読み直す
  const remaining = manaRemaining(state);
  const isFirstYear = state.day <= 24;
  const cleanCost = isFirstYear ? 500 : 1000;

  document.getElementById('poopComment').textContent = c.poopCount >= 3 ? t('poop_comment_3') : '';
  document.getElementById('poopTitle').textContent = t('barn_poop_title');

  const selfBtn = document.getElementById('poopBtnSelf');
  selfBtn.textContent = t('barn_poop_option_self');
  selfBtn.disabled = remaining < 4;

  const shopBtn = document.getElementById('poopBtnShop');
  shopBtn.textContent = t('barn_poop_option_shop').replace('{cost}', cleanCost);
  shopBtn.disabled = state.money < cleanCost;

  document.getElementById('poopBtnCancel').textContent = t('barn_poop_cancel');
  document.getElementById('poopSheetOverlay').classList.add('open');
}

function closePoopSheet() {
  document.getElementById('poopSheetOverlay').classList.remove('open');
  currentPoopStall = null;
}

function confirmPoopSelf() {
  if (!currentPoopStall) return;
  const state = loadLoopState();
  if (manaRemaining(state) < 4) return;
  state.manaUsed = (state.manaUsed || 0) + 4;
  const targetCow = state.cows.find(c => c.id === cow.id);
  if (targetCow) targetCow.poopCount = 0;
  saveLoopState(state);
  cow.poopCount = 0; // 表示中のcowオブジェクト（drawが参照）にも反映
  closePoopSheet();
}

function confirmPoopShop() {
  if (!currentPoopStall) return;
  const state = loadLoopState();
  const isFirstYear = state.day <= 24;
  const cleanCost = isFirstYear ? 500 : 1000;
  if (state.money < cleanCost) return;
  state.money -= cleanCost;
  const targetCow = state.cows.find(c => c.id === cow.id);
  if (targetCow) targetCow.poopCount = 0;
  saveLoopState(state);
  cow.poopCount = 0;
  closePoopSheet();
}

// ── 起動 ──
async function initBarn() {
  await loadDict();

  renderHeader('gameHeader');
  document.getElementById('btn-back').textContent = t('btn_go_home');
  document.getElementById('btn-back').addEventListener('click', () => { location.href = 'home.html'; });

  await Promise.all([
    loadImg('barn_bg', 'data:image/png;base64,'),
    loadImg('player_down', 'assets/sprites/char_down.png'),
    loadImg('player_up', 'assets/sprites/char_up.png'),
    loadImg('player_left', 'assets/sprites/char_left.png'),
    loadImg('player_right', 'assets/sprites/char_right.png'),
    loadImg('player_walk_down', 'assets/sprites/char_walk_down.png'),
    loadImg('player_walk_left', 'assets/sprites/char_walk_left.png'),
    loadImg('player_walk_right', 'assets/sprites/char_walk_right.png'),
  ]);
  await preRenderCow(cow.seed);
  loop();
}
initBarn();
